import React, { useState, useEffect } from 'react';
import api from '../services/api';

function Home() {
    const [osList, setOsList] = useState([]);
    const [filtroNumero, setFiltroNumero] = useState('');
    const [filtroStatus, setFiltroStatus] = useState('todos');
    const [filtroCliente, setFiltroCliente] = useState('');
    const [pagina, setPagina] = useState(1);
    const itensPorPagina = 10;

    useEffect(() => {
        carregarOS();
    }, []);

    const carregarOS = async () => {
        try {
            const res = await api.get('/os');
            setOsList(res.data);
        } catch (err) {
            console.error(err);
            // Simula dados para não ficar vazio enquanto o backend não estiver 100%
            setOsList([]);
        }
    };

    // Filtros
    const osFiltradas = osList.filter(os => {
        if (filtroNumero && !os.numero_os?.toLowerCase().includes(filtroNumero.toLowerCase())) return false;
        if (filtroStatus === 'abertos' && os.status_os === 'concluido') return false;
        if (filtroStatus === 'concluidos' && os.status_os !== 'concluido') return false;
        if (filtroCliente && !os.cliente_nome?.toLowerCase().includes(filtroCliente.toLowerCase())) return false;
        return true;
    });

    // Paginação
    const totalPaginas = Math.ceil(osFiltradas.length / itensPorPagina);
    const osExibidas = osFiltradas.slice((pagina-1)*itensPorPagina, pagina*itensPorPagina);

    const finalizarOS = async (id) => {
        if (window.confirm('Finalizar esta OS? O cronômetro será encerrado.')) {
            try {
                await api.put(`/os/${id}`, { status_os: 'concluido' });
                carregarOS();
            } catch (err) {
                alert('Erro ao finalizar OS');
            }
        }
    };

    return (
        <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
            {/* Título em destaque */}
            <div style={{ textAlign: 'center', marginBottom: '30px' }}>
                <h1 style={{ 
                    fontSize: '32px', 
                    fontWeight: 'bold', 
                    textTransform: 'uppercase',
                    backgroundColor: '#1e3c72',
                    color: 'white',
                    padding: '15px',
                    borderRadius: '8px',
                    display: 'inline-block',
                    boxShadow: '0 4px 8px rgba(0,0,0,0.2)'
                }}>
                    📊 DASHBOARD - MWR SISTEMA
                </h1>
            </div>

            {/* Filtros */}
            <div style={{ display: 'flex', gap: '15px', flexWrap: 'wrap', marginBottom: '25px', background: '#f5f5f5', padding: '15px', borderRadius: '8px' }}>
                <input 
                    type="text" 
                    placeholder="🔍 Nº da OS" 
                    value={filtroNumero} 
                    onChange={e => setFiltroNumero(e.target.value)}
                    style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ccc' }}
                />
                <select value={filtroStatus} onChange={e => setFiltroStatus(e.target.value)} style={{ padding: '8px', borderRadius: '5px' }}>
                    <option value="todos">Todos os status</option>
                    <option value="abertos">Somente abertos</option>
                    <option value="concluidos">Somente concluídos</option>
                </select>
                <input 
                    type="text" 
                    placeholder="👤 Nome do cliente" 
                    value={filtroCliente} 
                    onChange={e => setFiltroCliente(e.target.value)}
                    style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ccc' }}
                />
            </div>

            {/* Tabela de OS */}
            <div style={{ overflowX: 'auto' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
                    <thead style={{ backgroundColor: '#2c3e50', color: 'white' }}>
                        <tr>
                            <th style={{ padding: '12px' }}>Nº OS</th>
                            <th style={{ padding: '12px' }}>Cliente</th>
                            <th style={{ padding: '12px' }}>Equipamento</th>
                            <th style={{ padding: '12px' }}>Status</th>
                            <th style={{ padding: '12px' }}>Valor (R$)</th>
                            <th style={{ padding: '12px' }}>Ações</th>
                        </tr>
                    </thead>
                    <tbody>
                        {osExibidas.length === 0 ? (
                            <tr><td colSpan="6" style={{ textAlign: 'center', padding: '20px' }}>Nenhuma OS encontrada</td></tr>
                        ) : (
                            osExibidas.map(os => (
                                <tr key={os.id} style={{ borderBottom: '1px solid #ddd', backgroundColor: os.status_os === 'concluido' ? '#e8f5e9' : '#fff' }}>
                                    <td style={{ padding: '10px' }}>{os.numero_os}</td>
                                    <td style={{ padding: '10px' }}>{os.cliente_nome}</td>
                                    <td style={{ padding: '10px' }}>{os.equipamento} {os.modelo}</td>
                                    <td style={{ padding: '10px' }}>
                                        <span style={{
                                            backgroundColor: os.status_os === 'concluido' ? '#4caf50' : '#ff9800',
                                            color: 'white',
                                            padding: '4px 8px',
                                            borderRadius: '12px',
                                            fontSize: '12px'
                                        }}>
                                            {os.status_os === 'concluido' ? 'CONCLUÍDO' : 'ABERTO'}
                                        </span>
                                    </td>
                                    <td style={{ padding: '10px' }}>R$ {parseFloat(os.preco_final || 0).toFixed(2)}</td>
                                    <td style={{ padding: '10px' }}>
                                        <button style={{ marginRight: '5px', padding: '5px 10px', backgroundColor: '#2196f3', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }} onClick={() => alert(`Detalhes da OS ${os.numero_os}`)}>Ver</button>
                                        <button style={{ marginRight: '5px', padding: '5px 10px', backgroundColor: '#ffc107', color: 'black', border: 'none', borderRadius: '4px', cursor: 'pointer' }} onClick={() => alert(`Editar OS ${os.numero_os}`)}>Editar</button>
                                        {os.status_os !== 'concluido' && (
                                            <button style={{ padding: '5px 10px', backgroundColor: '#dc3545', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }} onClick={() => finalizarOS(os.id)}>Finalizar</button>
                                        )}
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {/* Paginação */}
            {totalPaginas > 1 && (
                <div style={{ display: 'flex', justifyContent: 'center', gap: '15px', marginTop: '25px' }}>
                    <button onClick={() => setPagina(p => Math.max(1, p-1))} disabled={pagina === 1} style={{ padding: '8px 16px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>Anterior</button>
                    <span>Página {pagina} de {totalPaginas}</span>
                    <button onClick={() => setPagina(p => Math.min(totalPaginas, p+1))} disabled={pagina === totalPaginas} style={{ padding: '8px 16px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>Próxima</button>
                </div>
            )}
        </div>
    );
}

export default Home;
